BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?inst ?name ?spec WHERE {
  ?elem vocab:NamedElement_name "Peak%20Power%20Limit%20Requirement%20TMT" .
  ?elem vocab:Classifier__instanceSpecificationOfClassifier ?inst .
  ?inst vocab:NamedElement_name ?name .
  OPTIONAL { ?inst vocab:InstanceSpecification_specification ?spec }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?prop ?name ?type ?default WHERE {
  ?prop vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("powerPeakLimit"))) 
  ?prop rdf:type ?type .
  OPTIONAL { ?prop vocab:Property_defaultValue ?default }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?dep ?clientName ?supplierName WHERE {
  ?dep rdf:type vocab:satisfy .
  OPTIONAL { ?dep vocab:Dependency_client ?client .
  ?client vocab:NamedElement_name ?clientName }
  OPTIONAL { ?dep vocab:Dependency_supplier ?supplier .
  ?supplier vocab:NamedElement_name ?supplierName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
