SELECT ?attr ?name ?type WHERE {
  ?elem vocab:NamedElement_name "Satisfy%20Peak%20Power%20Explanation" .
  ?elem vocab:Element_ownedElement ?attr .
  ?attr rdf:type ?type .
  OPTIONAL { ?attr vocab:NamedElement_name ?name }
}
LIMIT 50
